class Solution {
public:
    int findIntegers(int n) {
        int f[31] = {0};
        f[0] = 1;
        f[1] = 2;
        for (int i = 2; i < 31; ++i) {
            f[i] = f[i - 1] + f[i - 2];
        }
        int ans = 0, pre = 0;
        for (int i = 29; i >= 0; --i) {
            if ((n >> i) & 1) {
                ans += f[i];
                if (pre == 1) {
                    return ans;
                }
                pre = 1;
            } else {
                pre = 0;
            }
        }
        return ans + 1;
    }
};
efficiency: HIGH
time complexity: O(log n)
space complexity: O(log n)
energy implications: LOW
explanation: Utilizes dynamic programming to pre-calculate Fibonacci sequence values representing counts of numbers without consecutive ones for each bit position, then iterates through the bits of the given number n to count valid numbers up to n.
